"""Tests for tray supervisor: stop/restart dispatch per platform."""

from unittest.mock import MagicMock, patch

import pytest

from agentpulse.tray import supervisor


def test_stop_linux_calls_systemctl(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setattr("sys.platform", "linux")
    with patch("subprocess.run") as run:
        run.return_value.returncode = 0
        supervisor.stop_service()
    run.assert_called_once_with(
        ["systemctl", "--user", "stop", "agentpulse"], check=False
    )


def test_restart_linux_calls_systemctl(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setattr("sys.platform", "linux")
    with patch("subprocess.run") as run:
        run.return_value.returncode = 0
        supervisor.restart_service()
    run.assert_called_once_with(
        ["systemctl", "--user", "restart", "agentpulse"], check=False
    )


def test_stop_windows_terminates_matching_process(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setattr("sys.platform", "win32")

    fake_proc = MagicMock()
    fake_proc.info = {"name": "agentpulse.exe", "cmdline": ["agentpulse.exe"]}

    with patch("psutil.process_iter", return_value=[fake_proc]):
        supervisor.stop_service()

    fake_proc.terminate.assert_called_once()


def test_restart_windows_terminates_then_launches(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setattr("sys.platform", "win32")
    fake_proc = MagicMock()
    fake_proc.info = {"name": "agentpulse.exe", "cmdline": ["agentpulse.exe"]}
    monkeypatch.setattr(
        supervisor.shutil, "which", lambda _: "C:\\fake\\agentpulse.exe"
    )

    with (
        patch("psutil.process_iter", return_value=[fake_proc]),
        patch("subprocess.Popen") as popen,
    ):
        supervisor.restart_service()

    fake_proc.terminate.assert_called_once()
    popen.assert_called_once()
    cmd = popen.call_args[0][0]
    assert "agentpulse.exe" in cmd[0]


